//! Phase 3 Task 7 (Wave 2): flow-pipeline bit-parity replay against
//! `fixtures/flow.json`, generated by `tools/port/gen_flow_fixtures.py` in
//! the `cl_revenue_ops-port` worktree from the real
//! `modules/flow_analysis.py`.

use revops_analytics::classification::ChannelState;
use revops_analytics::flow::{
    apply_kalman_filter, apply_kalman_reclassification, calculate_adaptive_decay,
    calculate_ema_flow, calculate_velocity, update_temporal_profile, EmaBucket,
    HourlyHistogramBucket, KalmanFilterOutcome, KalmanStep, ReclassificationInput, TemporalProfile,
    BASE_EMA_DECAY, DECAY_RANGE, MAX_VELOCITY, MIN_VELOCITY, TEMPORAL_EMA_ALPHA,
    TEMPORAL_GRADUATION_DAYS, TEMPORAL_MIN_DAILY_FORWARDS, VELOCITY_OUTLIER_THRESHOLD,
};
use revops_analytics::kalman::{DailyBucket, KalmanFlowFilter, KalmanFlowState, NetFlowEntry};
use serde_json::Value;

fn fixture() -> Value {
    let raw = include_str!("../../../fixtures/flow.json");
    serde_json::from_str(raw).unwrap()
}

fn bits_to_f64(s: &str) -> f64 {
    assert_eq!(s.len(), 16, "expected a 16-hex-char bit pattern, got {s:?}");
    let mut bytes = [0u8; 8];
    for (i, byte) in bytes.iter_mut().enumerate() {
        *byte = u8::from_str_radix(&s[i * 2..i * 2 + 2], 16).expect("valid hex byte");
    }
    f64::from_bits(u64::from_le_bytes(bytes))
}

fn f64_bits(v: &Value) -> f64 {
    bits_to_f64(v.as_str().expect("expected a hex bit-pattern string"))
}

fn assert_bits_eq(actual: f64, expected: f64, label: &str) {
    assert_eq!(
        actual.to_bits(),
        expected.to_bits(),
        "{label}: bit mismatch (actual={actual:?} [{:016x}], expected={expected:?} [{:016x}])",
        actual.to_bits(),
        expected.to_bits(),
    );
}

fn daily_buckets_from(v: &Value) -> Vec<DailyBucket> {
    v.as_array()
        .unwrap()
        .iter()
        .map(|b| DailyBucket {
            out: b["out"].as_f64().unwrap(),
            in_: b["in"].as_f64().unwrap(),
        })
        .collect()
}

fn state_from_json(v: &Value) -> KalmanFlowState {
    KalmanFlowState {
        flow_ratio: f64_bits(&v["flow_ratio"]),
        flow_velocity: f64_bits(&v["flow_velocity"]),
        variance_ratio: f64_bits(&v["variance_ratio"]),
        variance_velocity: f64_bits(&v["variance_velocity"]),
        covariance: f64_bits(&v["covariance"]),
        last_update: v["last_update"].as_i64().unwrap(),
        innovation_variance: f64_bits(&v["innovation_variance"]),
        last_innovation: f64_bits(&v["last_innovation"]),
        observation_count: v["observation_count"].as_i64().unwrap(),
    }
}

fn step_from_str(s: &str) -> KalmanStep {
    match s {
        "untouched" => KalmanStep::Untouched,
        "updated" => KalmanStep::Updated,
        "predict_only" => KalmanStep::PredictOnly,
        other => panic!("unknown step label {other}"),
    }
}

