#[test]
fn constants_match_python_bit_for_bit() {
    let c = &fixture()["constants"];
    assert_bits_eq(MAX_VELOCITY, f64_bits(&c["MAX_VELOCITY"]), "MAX_VELOCITY");
    assert_bits_eq(MIN_VELOCITY, f64_bits(&c["MIN_VELOCITY"]), "MIN_VELOCITY");
    assert_bits_eq(
        VELOCITY_OUTLIER_THRESHOLD,
        f64_bits(&c["VELOCITY_OUTLIER_THRESHOLD"]),
        "VELOCITY_OUTLIER_THRESHOLD",
    );
    assert_bits_eq(
        BASE_EMA_DECAY,
        f64_bits(&c["BASE_EMA_DECAY"]),
        "BASE_EMA_DECAY",
    );
    assert_bits_eq(DECAY_RANGE, f64_bits(&c["DECAY_RANGE"]), "DECAY_RANGE");
    assert_bits_eq(
        TEMPORAL_EMA_ALPHA,
        f64_bits(&c["TEMPORAL_EMA_ALPHA"]),
        "TEMPORAL_EMA_ALPHA",
    );
    assert_eq!(
        TEMPORAL_GRADUATION_DAYS,
        c["TEMPORAL_GRADUATION_DAYS"].as_i64().unwrap()
    );
    assert_eq!(
        TEMPORAL_MIN_DAILY_FORWARDS,
        c["TEMPORAL_MIN_DAILY_FORWARDS"].as_i64().unwrap()
    );
}

